import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"54. Personal Carer S Leave","description":"","frontmatter":{"title":"54. Personal Carer S Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","personal-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/54-personal-carer-s-leave.md","filePath":"ebas/biomedical-engineers/leave/54-personal-carer-s-leave.md"}'),n={name:"ebas/biomedical-engineers/leave/54-personal-carer-s-leave.md"};function s(i,e,l,p,h,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_54-personal-carer-s-leave" tabindex="-1">54. Personal Carer S Leave <a class="header-anchor" href="#_54-personal-carer-s-leave" aria-label="Permalink to &quot;54. Personal Carer S Leave&quot;">​</a></h1><p>The provisions of this clause apply to full-time and part-time Employees. See subclause</p><p><strong>54.8</strong> for casual Employees’ entitlements.</p><p><strong>54.1</strong> Access to Personal/Carer’s Leave Subject to the conditions set out in this clause, an Employee may take paid personal/carer’s leave if the leave is taken:</p><p><strong>(a)</strong> due to personal illness or injury (sick leave); or</p><p><strong>(b)</strong> To care for or support to a member of the Employee’s Immediate Family or household because of:</p><p><strong>(i)</strong> a personal illness or injury affecting them; or</p><p><strong>(ii)</strong> an unexpected emergency affecting them (carer’s leave).</p><p><strong>54.2</strong> Amount of Paid Personal/Carer’s Leave</p><p><strong>(a)</strong> An Employee is entitled to the following amount of paid personal leave:</p><p><strong>(i)</strong> 91.2 hours in the first year of service;</p><p><strong>(ii)</strong> 106.4 hours in each year in the second, third and fourth years of service; and</p><p><strong>(iii)</strong> 159.6 hours in each year in the fifth and subsequent years of service.</p><p><strong>(b)</strong> Paid personal leave accrues progressively during a year of service according to the Employee’s ordinary hours of work, and accumulates from year to year.</p><p><strong>(c)</strong> The entitlement for a part-time Employee accrues on a pro-rata basis.</p><p><strong>54.3</strong> Payment for leave</p><p><strong>(a)</strong> Payment will be made based on the Employee’s ordinary pay for the ordinary hours the Employee would have worked on the day or days on which the leave was taken.</p><p><strong>(b)</strong> An Employee utilising personal leave may take leave for part of a single day. Leave will be deducted from the Employee’s accrued personal leave including, where relevant, for a part day.</p><p><strong>54.4</strong> Sick Leave</p><p><strong>(a)</strong> Evidence requirements</p><p><strong>(i)</strong> An Employee taking sick leave will, as soon as reasonably practicable, give the Employer evidence that would satisfy a reasonable person the Employee is absent due to personal illness or injury. Evidence that would satisfy a reasonable person that the Employee is absent due to personal illness or injury includes: <strong>(A)</strong> a medical certificate from a Registered Health Practitioner; or <strong>(B)</strong> Commonwealth or Victorian Statutory Declaration signed by the Employee.</p><p><strong>(ii)</strong> Exception to evidence requirement – absences without evidence as required at subclause 54.4(a)(i) <strong>(A)</strong> Excluding Employees at the Royal Children’s Hospital and the Royal Women’s Hospital An Employee may be absent for a single day or part thereof without evidence of personal illness or injury on not more than three occasions per year of service. <strong>(B)</strong> Employees at the Royal Children’s Hospital and the Royal Women’s Hospital only An Employee may be absent on six (6) days per year of service (either as single days or as two days at a time) without evidence of personal illness or injury. If the Employee is not absent as provided in clause 54.4(a)(ii)(B) above, they will be credited with one (1) day of annual leave for every two (2) days of personal leave not taken and the Employee&#39; sick leave balance shall be reduced in a proportion of two to one, for each additional days leave so credited. However, if the Employee advises the Employer (in writing) not less than four (4) weeks prior to the conclusion of any one year, they may elect to retain the unused sick leave as accrued sick leave entitlements.</p><p><strong>(b)</strong> Notice requirements An Employee should inform the Employer of their absence at least two hours prior to the commencement of duty on the first day of absence, or otherwise as soon as reasonably practicable (which may be a time after the leave has started), and advise of the duration or estimated duration of the absence.</p><p><strong>54.5</strong> Carer’s Leave</p><p><strong>(a)</strong> Evidence Requirements The Employee must, if required by the Employer, establish by production of a Commonwealth or Victorian statutory declaration, a medical certificate from a Registered Health Practitioner or other evidence that would satisfy a reasonable person that a member of the Employee’s Immediate Family or household has either:</p><p><strong>(i)</strong> an illness or injury; or</p><p><strong>(ii)</strong> an unexpected emergency; that requires their care or support. In the case of an unexpected emergency, the Employee will identify the nature of the emergency.</p><p><strong>(b)</strong> Notice requirements</p><p><strong>(i)</strong> The Employee must, where practicable, give the Employer notice of the intention to take leave prior to the absence that includes: <strong>(A)</strong> the relationship to the Employee of the person requiring care or support; <strong>(B)</strong> The reasons for taking such leave; and <strong>(C)</strong> The estimated length of absence.</p><p><strong>(ii)</strong> If it is not reasonably practicable for the Employee to give prior notice of absence, the Employee must notify the Employer of the absence as soon as practicable.</p><p><strong>(c)</strong> Unpaid carer’s leave An Employee who has exhausted all paid personal/carer’s leave entitlements is entitled to take unpaid carer’s leave. The Employer and the Employee will agree on the period. In the absence of agreement, the Employee is entitled to take up to two (2) days’ unpaid carer’s leave per occasion, provided the notice and evidence requirements are met.</p><p><strong>54.6</strong> Personal leave on a public holiday If the period during which an Employee takes paid personal/carer’s leave includes a day or part day that is a public holiday in the place where the Employee is based for work purposes, the Employee is taken not to be on paid personal/carer’s leave on that public holiday.</p><p><strong>54.7</strong> Portability of Personal Leave</p><p><strong>(a)</strong> Entitlement - Employees at the Royal Children’s Hospital and the Royal Women’s Hospital only</p><p><strong>(i)</strong> For the purposes of this subclause 54.7(a), allowable period of absence means: <strong>(A)</strong> five weeks in addition to the total period of annual leave, long service leave and/or personal/carers leave which the Employee actually receives on termination or for which they are paid in lieu; and <strong>(B)</strong> any unpaid absence of up to 52 weeks taken for the sole purpose of undertaking a course of study related to their employment.</p><p><strong>(ii)</strong> Where an Employee is or has been in the service of an institution or statutory body recognised under the Nurses (Victorian Health Services) Award 2000, and commences employment with an (or another) Employer before the end of the allowable period of absence, the Employer will credit the Employee’s accumulated personal leave from the previous employer up to a maximum of 1368 hours to the Employee in their new employment.</p><p><strong>(b)</strong> Entitlement - Excluding Employees at the Royal Children’s Hospital and the Royal Women’s Hospital</p><p><strong>(i)</strong> Where an Employee is or has been in the service of another employer specified at subclause 54.7(b)(ii), and commences employment with an (or another) Employer, the Employer will credit the Employee’s accumulated personal leave from the previous employer up to a maximum of 2128 hours to the Employee in their new employment as accumulated personal/carer’s leave.</p><p><strong>(ii)</strong> The specified employers are: <strong>(A)</strong> Albury Wodonga Health (Wodonga Hospital);</p><p><strong>(B)</strong> Alfred Health; <strong>(C)</strong> Austin Health; <strong>(D)</strong> Barwon Health; <strong>(E)</strong> Eastern Health; <strong>(F)</strong> Goulburn Valley Health; <strong>(G)</strong> Latrobe Regional Health; <strong>(H)</strong> Melbourne Health; <strong>(I)</strong> Mercy Public Hospitals Inc; <strong>(J)</strong> Northern Health <strong>(K)</strong> Peter MacCallum Cancer Centre; <strong>(L)</strong> Royal Children’s Hospital <strong>(M)</strong> Royal Women’s Hospital; <strong>(N)</strong> South West Healthcare; <strong>(O)</strong> Monash Health; <strong>(P)</strong> Western Health.</p><p><strong>(c)</strong> Evidence The Employer may require the Employee to produce a written statement from their previous employer specifying the amount of accumulated personal/carer’s leave at the time of leaving that previous employment.</p><p><strong>54.8</strong> Casual Employees – Caring responsibilities</p><p><strong>(a)</strong> Subject to the evidence and notice requirements that apply to carer’s leave under subclause 54.5, a Casual Employee is entitled to be unavailable to attend work, or to leave work, if they need to care or support a member of their Immediate Family or household because of:</p><p><strong>(i)</strong> a personal illness, or personal injury, affecting them;</p><p><strong>(ii)</strong> an unexpected emergency affecting them; or</p><p><strong>(iii)</strong> the birth of a child.</p><p><strong>(b)</strong> The Employer and Employee will agree on the period for which the Employee will be entitled to be unavailable to attend work. In the absence of agreement, the Employee is entitled to be unavailable to attend work for up to two (2) days per occasion, which may be taken as a single continuous period of up to two (2) days or any separate periods to which the Employer and Employee agree.</p><p><strong>(c)</strong> A casual Employee is not entitled to any payment for the period of non-attendance.</p>',48)])])}const g=o(n,[["render",s]]);export{d as __pageData,g as default};
